  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
  assertTransition(claim.status, 'UNDER_REVIEW');

  claim.status = 'UNDER_REVIEW';
  await claim.save();

  eventBus.emit(EVENTS.CLAIM_REVIEW_STARTED, { claimId: claim._id, actorId });

  return adjudicateClaim(claimId, 'INITIAL_SUBMISSION', actorId);
}

// Mark as PAID. No limit ledger changes — consumption happened at adjudication.
async function payClaim(claimId) {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
  assertTransition(claim.status, 'PAID');

  claim.status = 'PAID';
  await claim.save();

  eventBus.emit(EVENTS.CLAIM_PAID, { claimId: claim._id, memberId: claim.memberId });
  return claim;
}

// disputedItemIds: which line items are contested; empty means the entire claim is disputed.
// Returns the updated claim with a convenience `disputeReason` property attached.
async function disputeClaim(claimId, reason, disputedItemIds = []) {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
  assertTransition(claim.status, 'DISPUTED');

  const dispute = new Dispute({
    claimId: claim._id,
    memberId: claim.memberId,
    disputedItemIds,
    reason
  });
  await dispute.save();

  claim.status = 'DISPUTED';
  claim.activeDisputeId = dispute._id;
  await claim.save();

  eventBus.emit(EVENTS.DISPUTE_FILED, {
    disputeId: dispute._id,
    claimId: claim._id,
    memberId: claim.memberId,
    disputedItemIds,
    reason
  });

  // Return the claim object with disputeReason attached for callers that need it inline.
  const result = claim.toObject();
  result.disputeReason = reason;
  return result;
}

// Reprocess: release prior consumed limits, reset items, re-adjudicate.
// Only allowed before PAID — once paid, reversals require a separate financial flow.
async function reprocessClaim(claimId, triggeringEvent = 'APPEAL', actorId = 'system') {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });

  const reprocessableStatuses = ['APPROVED', 'PARTIALLY_APPROVED', 'DENIED', 'DISPUTED'];
  if (claim.status === 'PAID') {
    throw Object.assign(
      new Error('Cannot reprocess a paid claim. File a financial adjustment instead.'),
      { statusCode: 422 }
    );
  }
  if (!reprocessableStatuses.includes(claim.status)) {
    throw Object.assign(
      new Error(`Cannot reprocess a claim in status ${claim.status}. Claim must be adjudicated first.`),
      { statusCode: 422 }
    );
  }

  const priorStatus = claim.status;
  let releasedItems = [];

  const session = await mongoose.startSession();
  try {
    await session.withTransaction(async () => {
      // Find all active (non-superseded) approved decisions for this claim
      const approvedDecisions = await ClaimDecision.find({
        claimId: claim._id,
        supersededBy: null,
        approvedAmount: { $gt: 0 }
      }).session(session);

      // Release limit consumption for each approved item
      releasedItems = approvedDecisions.map(d => ({
        benefitCategory: claim.items.id(d.claimItemId)?.benefitCategory,
        claimItemId: d.claimItemId,
        amount: d.approvedAmount
      })).filter(c => c.benefitCategory);

      await limitService.releaseAllForClaim(
        claim.policyId,
        claim.memberId,
        claim.dateOfService,
        claim._id,
        releasedItems,
        session
      );

      // Reset all item statuses
      for (const item of claim.items) {
        item.status = 'PENDING';
      }
      claim.status = 'UNDER_REVIEW';
      await claim.save({ session });
    });
  } finally {
    await session.endSession();
  }

  // Emit release events after the transaction commits.
  for (const item of releasedItems) {
    eventBus.emit(EVENTS.BENEFIT_LIMIT_RELEASED, {
      policyId: claim.policyId,
      memberId: claim.memberId,
      benefitCategory: item.benefitCategory,
      claimItemId: item.claimItemId,
      amount: item.amount,
      claimId: claim._id
    });
  }

  const result = await adjudicateClaim(claimId, triggeringEvent, actorId);

  eventBus.emit(EVENTS.CLAIM_REPROCESSED, {
    claimId: claim._id,
    triggeringEvent,
    priorStatus,
    newStatus: result.claimStatus,
    actorId
  });

  return result;
}

module.exports = { submitClaim, reviewClaim, payClaim, disputeClaim, reprocessClaim };

module.exports = {
  // Claim lifecycle
  CLAIM_SUBMITTED:      'ClaimSubmitted',
  CLAIM_REVIEW_STARTED: 'ClaimReviewStarted',
  CLAIM_ADJUDICATED:    'ClaimAdjudicated',
  CLAIM_PAID:           'ClaimPaid',
  CLAIM_REPROCESSED:    'ClaimReprocessed',

  // Per-item decisions
  ITEM_DECISION_MADE:   'ItemDecisionMade',
  DECISION_SUPERSEDED:  'DecisionSuperseded',

  // Benefit limits
  BENEFIT_LIMIT_CONSUMED:  'BenefitLimitConsumed',
  BENEFIT_LIMIT_RELEASED:  'BenefitLimitReleased',
  BENEFIT_LIMIT_EXHAUSTED: 'BenefitLimitExhausted',

  // Disputes
  DISPUTE_FILED: 'DisputeFiled',
};

